import { useEffect, useRef, useState } from 'react';
import { trapFocus } from '../a11y/trap-focus';
import './help.css';

interface Props { onClose: () => void; initialTab?: 'keys' | 'techniques'; }

interface Shortcut { keys: string; desc: string; }

const SHORTCUTS: ReadonlyArray<Shortcut> = [
  { keys: '←  ↑  →  ↓',  desc: 'Move keyboard cursor around the board' },
  { keys: 'Space',         desc: 'Fill the focused cell (toggles)' },
  { keys: 'X',             desc: 'Mark focused cell with a cross (toggles)' },
  { keys: 'Backspace / Delete', desc: 'Clear focused cell' },
  { keys: 'M',             desc: 'Toggle primary mark (fill ⇄ cross)' },
  { keys: 'Z',             desc: 'Undo last move' },
  { keys: 'Y or Shift+Z',  desc: 'Redo' },
  { keys: 'H',             desc: 'Request a hint' },
  { keys: 'R',             desc: 'Restart the current puzzle (confirms)' },
  { keys: '?',             desc: 'Open this help sheet' },
  { keys: 'Esc',           desc: 'Close any open dialog' },
];

interface Technique { title: string; body: string; }

const TECHNIQUES: ReadonlyArray<Technique> = [
  {
    title: 'Overlap (forced fills)',
    body: 'If a single clue’s minimum slide-left and slide-right placements overlap, every overlapping cell must be filled. Example: a "4" in a 5-cell row forces cells 2,3,4 (1-indexed) to fill.',
  },
  {
    title: 'Edge logic',
    body: 'A run that touches the edge of the line is pinned. If the first clue is "3", at least the first 3 cells are fill candidates — combine with adjacent crosses to lock them in.',
  },
  {
    title: 'Gaps & remainders',
    body: 'Sum the clues and the mandatory single-cell gaps between them. The slack (line length − minimum) is the wiggle room for every clue. Less slack = more deductions.',
  },
  {
    title: 'Completed-clue elimination',
    body: 'Once a clue is fully placed and bounded by crosses, no other clues can touch it. Cross out cells that would extend a satisfied run.',
  },
  {
    title: 'Intersection (cross-line)',
    body: 'When one direction tells you a cell is fill, check the perpendicular line — the new info may unlock a forced placement there too. Always cycle rows ⇄ columns when stuck.',
  },
  {
    title: 'Hard-mode strategy',
    body: 'With limited strikes, never guess. Always confirm a fill or cross deductively; mark possibilities lightly with crosses first, fill last.',
  },
];

/**
 * Help sheet — two tabs: keyboard shortcuts cheatsheet, and a deeper
 * nonogram-techniques crash course. Lazy-loaded.
 */
export function HelpSheet({ onClose, initialTab = 'keys' }: Props) {
  const ref = useRef<HTMLDivElement>(null);
  const [tab, setTab] = useState<'keys' | 'techniques'>(initialTab);

  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const release = trapFocus(node);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  return (
    <div className="etch-help-backdrop" role="dialog" aria-modal="true" aria-label="Help center" onClick={onClose}>
      <div className="etch-help-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
        <header>
          <h2>Help</h2>
          <button className="etch-help-close" aria-label="Close" onClick={onClose}>×</button>
        </header>
        <div className="etch-help-tabs" role="tablist">
          <button
            role="tab"
            aria-selected={tab === 'keys'}
            className={`etch-help-tab${tab === 'keys' ? ' is-active' : ''}`}
            onClick={() => setTab('keys')}
            type="button"
          >
            Keyboard shortcuts
          </button>
          <button
            role="tab"
            aria-selected={tab === 'techniques'}
            className={`etch-help-tab${tab === 'techniques' ? ' is-active' : ''}`}
            onClick={() => setTab('techniques')}
            type="button"
          >
            Techniques
          </button>
        </div>
        {tab === 'keys' ? (
          <section className="etch-help-keys" role="tabpanel" aria-label="Keyboard shortcuts">
            <ul>
              {SHORTCUTS.map(s => (
                <li key={s.keys}>
                  <kbd>{s.keys}</kbd>
                  <span>{s.desc}</span>
                </li>
              ))}
            </ul>
            <p className="etch-help-note">
              Touch users: tap to fill, long-press for cross, drag to mark many cells in one stroke.
            </p>
          </section>
        ) : (
          <section className="etch-help-tech" role="tabpanel" aria-label="Nonogram techniques">
            {TECHNIQUES.map(t => (
              <article key={t.title}>
                <h3>{t.title}</h3>
                <p>{t.body}</p>
              </article>
            ))}
          </section>
        )}
      </div>
    </div>
  );
}

export default HelpSheet;
